// ── STYLES ───────────────────────────────────────────────────────────────────
const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&family=Open+Sans:wght@300;400;500;600&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --pink:        #dd6ba6;
    --pink-light:  #f0a8cf;
    --pink-pale:   #fceef7;
    --peach:       #e5a983;
    --peach-pale:  #fdf0e8;
    --gold:        #f5da9e;
    --gold-pale:   #fff1c4;
    --cream:       #f8f1d9;
    --cream-light: #fdf9f0;
    --text:        #575756;
    --text-dark:   #3a3a39;
    --text-muted:  #9a9896;
    --white:       #ffffff;
    --radius-sm:   10px;
    --radius:      18px;
    --radius-lg:   28px;
    --shadow-sm:   0 2px 12px rgba(87,87,86,0.08);
    --shadow:      0 6px 30px rgba(87,87,86,0.13);
    --shadow-lg:   0 16px 60px rgba(87,87,86,0.18);
  }

  html, body { height: 100%; background: var(--cream); }

  body {
    font-family: 'Open Sans', sans-serif;
    color: var(--text-dark);
    max-width: 430px;
    margin: 0 auto;
    min-height: 100vh;
    position: relative;
    overflow-x: hidden;
  }

  h1, h2, h3, h4, h5, .nunito { font-family: 'Nunito', sans-serif; }

  /* ── SCROLL ── */
  .scroll-area {
    height: calc(100vh - 72px);
    scroll-behavior: smooth;
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
  }
  .scroll-area::-webkit-scrollbar { display: none; }

  /* ── TOP BAR ── */
  .topbar {
    position: sticky;
    top: 0;
    z-index: 100;
    background: var(--white);
    border-bottom: 1px solid rgba(87,87,86,0.1);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 20px;
    box-shadow: var(--shadow-sm);
  }
  .topbar-logo img {
    height: 28px;
    width: auto;
    display: block;
    background: transparent;
  }
  .topbar-sub {
    font-size: 0.65rem;
    color: var(--text-muted);
    font-weight: 600;
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-top: 2px;
  }

  /* ── BOTTOM NAV ── */
  .bottom-nav {
    position: fixed;
    bottom: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 100%;
    max-width: 430px;
    background: var(--white);
    border-top: 1px solid rgba(87,87,86,0.1);
    display: flex;
    z-index: 100;
    box-shadow: 0 -4px 20px rgba(87,87,86,0.1);
  }
  .nav-btn {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    padding: 8px 2px 10px;
    border: none;
    background: none;
    cursor: pointer;
    color: var(--text-muted);
    font-family: 'Open Sans', sans-serif;
    font-size: 0.58rem;
    font-weight: 600;
    letter-spacing: 0.2px;
    transition: color 0.2s;
  }
  .nav-btn.active { color: var(--pink); }

  .nav-btn svg { width: 20px; height: 20px; transition: transform 0.2s; }
  .nav-btn.active svg { transform: scale(1.1); }
  .nav-dot {
    width: 4px; height: 4px; border-radius: 50%;
    background: var(--pink);
    opacity: 0;
    transition: opacity 0.2s;
    margin-top: -2px;
  }
  .nav-btn.active .nav-dot { opacity: 1; }

  /* ── HOME TAB ── */
  .hero {
    background-image: url('data:image/jpeg;base64,');
    background-size: cover;
    background-position: center top;
    padding: 0 0 0 0;
    position: relative;
    overflow: hidden;
    min-height: 320px;
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
  }
  .hero::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(to bottom, rgba(0,0,0,0) 30%, rgba(0,0,0,0.65) 100%);
    z-index: 0;
  }
  .hero::after {
    content: none;
  }
  .hero > * {
    position: relative;
    z-index: 1;
  }
  .hero-content {
    padding: 24px 24px 32px;
  }
  .hero-eyebrow {
    font-size: 0.7rem;
    font-weight: 700;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--gold-pale);
    margin-bottom: 10px;
  }
  .hero h1 {
    font-size: 1.45rem;
    font-weight: 900;
    color: var(--white);
    line-height: 1.2;
    margin-bottom: 4px;
  }
  .hero h1 em {
    font-style: normal;
    color: var(--gold-pale);
  }
  .hero-desc {
    font-size: 0.88rem;
    color: rgba(255,255,255,0.88);
    line-height: 1.5;
    margin-bottom: 20px;
  }
  .hero-cta {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--white);
    color: var(--text-dark);
    font-family: 'Nunito', sans-serif;
    font-weight: 800;
    font-size: 0.9rem;
    padding: 13px 22px;
    border-radius: 50px;
    border: none;
    cursor: pointer;
    box-shadow: 0 4px 20px rgba(0,0,0,0.15);
    text-decoration: none;
    transition: transform 0.15s, box-shadow 0.15s;
  }
  .hero-cta:hover { transform: translateY(-1px); box-shadow: 0 6px 28px rgba(0,0,0,0.2); }

  .home-section { padding: 28px 20px 0; }
  .section-label {
    font-family: 'Nunito', sans-serif;
    font-weight: 800;
    font-size: 0.7rem;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    color: var(--text-muted);
    margin-bottom: 14px;
  }

  .feature-card {
    background: var(--white);
    border-radius: var(--radius);
    padding: 20px;
    margin-bottom: 14px;
    box-shadow: var(--shadow-sm);
    display: flex;
    align-items: center;
    gap: 16px;
    cursor: pointer;
    transition: transform 0.15s, box-shadow 0.15s;
    border: 1px solid rgba(87,87,86,0.07);
  }
  .feature-card:hover { transform: translateY(-2px); box-shadow: var(--shadow); }
  .feature-icon {
    width: 52px; height: 52px;
    border-radius: 14px;
    display: flex; align-items: center; justify-content: center;
    font-size: 1.4rem;
    flex-shrink: 0;
  }
  .feature-icon.pink  { background: var(--pink-pale); }
  .feature-icon.peach { background: var(--peach-pale); }
  .feature-icon.gold  { background: var(--gold-pale); }
  .feature-card h3 {
    font-size: 0.95rem;
    font-weight: 800;
    color: var(--text-dark);
    margin-bottom: 2px;
  }
  .feature-card p {
    font-size: 0.78rem;
    color: var(--text-muted);
    line-height: 1.4;
  }
  .feature-arrow { margin-left: auto; color: var(--text-muted); flex-shrink: 0; }

  /* ── KURS TAB ── */
  .kurs-header {
    background: linear-gradient(135deg, var(--gold-pale) 0%, var(--peach-pale) 100%);
    padding: 28px 20px 24px;
    border-bottom: 1px solid rgba(87,87,86,0.08);
  }
  .kurs-header h2 {
    font-size: 1.5rem;
    font-weight: 900;
    color: var(--text-dark);
    margin-bottom: 6px;
  }
  .kurs-header p {
    font-size: 0.83rem;
    color: var(--text);
    line-height: 1.5;
  }


  .modul {
    margin: 0 16px 16px;
    background: var(--white);
    border-radius: var(--radius);
    overflow: hidden;
    box-shadow: var(--shadow-sm);
    border: 1px solid rgba(87,87,86,0.07);
  }
  .modul-header {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 16px 18px;
    cursor: pointer;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
  }
  .modul-emoji {
    width: 10px; height: 10px;
    background: var(--pink);
    border-radius: 50%;
    flex-shrink: 0;
    margin-top: 6px;
  }
  .modul-title {
    font-family: 'Nunito', sans-serif;
    font-weight: 800;
    font-size: 0.95rem;
    color: var(--text-dark);
    flex: 1;
  }
  .modul-count {
    font-size: 0.72rem;
    color: var(--text-muted);
    margin-top: 1px;
  }
  .modul-chevron {
    color: var(--text-muted);
    transition: transform 0.25s;
    flex-shrink: 0;
  }
  .modul-chevron.open { transform: rotate(180deg); }

  .lektioner { border-top: 1px solid rgba(87,87,86,0.07); }
  .lektion {
    display: flex;
    align-items: center;
    gap: 14px;
    padding: 14px 18px;
    cursor: pointer;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    border-bottom: 1px solid rgba(87,87,86,0.05);
    transition: background 0.15s;
  }
  .lektion:last-child { border-bottom: none; }
  .lektion:hover { background: var(--cream); }
  .lektion-icon {
    width: 32px; height: 32px;
    border-radius: 8px;
    display: flex; align-items: center; justify-content: center;
    flex-shrink: 0;
    font-size: 0.9rem;
  }
  .lektion-icon.video { background: var(--pink-pale); color: var(--pink); }
  .lektion-icon.pdf   { background: var(--peach-pale); color: var(--peach); }
  .lektion-titel {
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--text-dark);
    line-height: 1.35;
    flex: 1;
  }
  .lektion-typ {
    font-size: 0.65rem;
    color: var(--text-muted);
    font-weight: 600;
    letter-spacing: 0.5px;
    text-transform: uppercase;
  }

  /* ── VIDEO MODAL ── */
  .modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(10,20,14,0.7);
    z-index: 200;
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    backdrop-filter: blur(4px);
    animation: fadeIn 0.2s ease;
  }
  @keyframes fadeIn { from { opacity: 0 } to { opacity: 1 } }

  .modal-sheet {
    background: var(--white);
    border-radius: var(--radius-lg) var(--radius-lg) 0 0;
    overflow: hidden;
    max-height: 92vh;
    animation: slideUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
  }
  @keyframes slideUp { from { transform: translateY(100%) } to { transform: translateY(0) } }

  .modal-handle {
    width: 40px; height: 4px;
    background: rgba(0,0,0,0.12);
    border-radius: 2px;
    margin: 12px auto 0;
  }
  .modal-top {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 18px 10px;
  }
  .modal-title {
    font-family: 'Nunito', sans-serif;
    font-weight: 800;
    font-size: 1rem;
    color: var(--text);
    flex: 1;
    padding-right: 12px;
    line-height: 1.3;
  }
  .modal-close {
    width: 32px; height: 32px;
    border-radius: 50%;
    background: var(--cream);
    border: none;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    color: var(--text-mid);
    flex-shrink: 0;
  }
  .video-wrapper {
    position: relative;
    padding-bottom: 56.25%;
    background: #000;
  }
  .video-wrapper iframe {
    position: absolute;
    inset: 0;
    width: 100%; height: 100%;
    border: none;
  }
  .pdf-placeholder {
    padding: 32px 20px;
    text-align: center;
  }
  .pdf-placeholder .pdf-icon {
    font-size: 3rem;
    margin-bottom: 12px;
  }
  .pdf-placeholder h3 {
    font-size: 1rem;
    font-weight: 800;
    color: var(--text);
    margin-bottom: 8px;
  }
  .pdf-placeholder p {
    font-size: 0.82rem;
    color: var(--text-muted);
    line-height: 1.5;
  }

  /* ── YOUTUBE TAB ── */
  .yt-header {
    background: #575756;
    padding: 28px 20px 24px;
  }
  .yt-header h2 {
    font-size: 1.4rem;
    font-weight: 900;
    color: white;
    margin-bottom: 6px;
  }
  .yt-header p {
    font-size: 0.83rem;
    color: rgba(255,255,255,0.85);
    line-height: 1.5;
  }
  .yt-cta {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: white;
    color: #dd6ba6;
    font-family: 'Nunito', sans-serif;
    font-weight: 800;
    font-size: 0.85rem;
    padding: 11px 20px;
    border-radius: 50px;
    border: none;
    cursor: pointer;
    margin-top: 16px;
    text-decoration: none;
    transition: transform 0.15s;
  }
  .yt-cta:hover { transform: scale(1.02); }

  .yt-info-card {
    margin: 16px;
    background: var(--white);
    border-radius: var(--radius);
    padding: 20px;
    box-shadow: var(--shadow-sm);
    border: 1px solid rgba(87,87,86,0.07);
    text-align: center;
  }
  .yt-info-card h3 {
    font-size: 1.05rem;
    font-weight: 800;
    color: var(--text);
    margin-bottom: 8px;
  }
  .yt-info-card p {
    font-size: 0.82rem;
    color: var(--text-muted);
    line-height: 1.55;
    margin-bottom: 16px;
  }
  .yt-open-btn {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: var(--peach);
    color: white;
    font-family: 'Nunito', sans-serif;
    font-weight: 800;
    font-size: 0.88rem;
    padding: 12px 22px;
    border-radius: 50px;
    border: none;
    cursor: pointer;
    text-decoration: none;
    transition: background 0.15s, transform 0.15s;
  }
  .yt-open-btn:hover { background: #d4916a; transform: translateY(-1px); }

  /* ── MEDL TAB ── */
  .medl-header {
    background: #dd6ba6;
    padding: 36px 20px 40px;
    text-align: center;
    position: relative;
    overflow: hidden;
  }
  .medl-header::before {
    content: '✦';
    position: absolute;
    top: 10px; right: 20px;
    font-size: 2rem;
    color: rgba(255,255,255,0.15);
  }
  .medl-header h2 {
    font-size: 1.6rem;
    font-weight: 900;
    color: white;
    line-height: 1.2;
    margin-bottom: 10px;
  }
  .medl-header p {
    font-size: 0.88rem;
    color: rgba(255,255,255,0.85);
    line-height: 1.6;
    margin-bottom: 24px;
  }
  .medl-cta {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    background: white;
    color: var(--text-dark);
    font-family: 'Nunito', sans-serif;
    font-weight: 900;
    font-size: 0.95rem;
    padding: 14px 26px;
    border-radius: 50px;
    border: none;
    cursor: pointer;
    box-shadow: 0 6px 24px rgba(0,0,0,0.2);
    text-decoration: none;
    transition: transform 0.15s, box-shadow 0.15s;
  }
  .medl-cta:hover { transform: translateY(-2px); box-shadow: 0 10px 32px rgba(0,0,0,0.25); }

  .inkl-section { padding: 20px 16px; }
  .inkl-title {
    font-family: 'Nunito', sans-serif;
    font-weight: 800;
    font-size: 0.75rem;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    color: var(--text-muted);
    margin-bottom: 12px;
    padding: 0 4px;
  }
  .inkl-item {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 14px 16px;
    background: var(--white);
    border-radius: var(--radius-sm);
    margin-bottom: 10px;
    box-shadow: var(--shadow-sm);
    border: 1px solid rgba(87,87,86,0.07);
  }
  .inkl-check {
    width: 24px; height: 24px;
    background: var(--pink-pale);
    border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    flex-shrink: 0;
    margin-top: 1px;
  }
  .inkl-check svg { color: var(--pink); }
  .inkl-item h4 {
    font-size: 0.88rem;
    font-weight: 700;
    color: var(--text-dark);
    margin-bottom: 2px;
  }
  .inkl-item p {
    font-size: 0.82rem;
    color: var(--text);
    line-height: 1.55;
  }

  .padding-bottom { padding-bottom: 80px; }
  input[type=range]::-webkit-slider-thumb {
    -webkit-appearance: none;
    width: 22px; height: 22px;
    border-radius: 50%;
    background: white;
    border: 3px solid #888;
    box-shadow: 0 1px 6px rgba(0,0,0,0.2);
    cursor: pointer;
    margin-top: -8px;
  }
  input[type=range]::-webkit-slider-runnable-track {
    height: 6px;
    border-radius: 3px;
  }
  input[type=range]::-moz-range-thumb {
    width: 22px; height: 22px;
    border-radius: 50%;
    background: white;
    border: 3px solid #888;
    box-shadow: 0 1px 6px rgba(0,0,0,0.2);
    cursor: pointer;
  }
  input[type=range]::-moz-range-track {
    height: 6px;
    border-radius: 3px;
  }
`;

