// ── APP ───────────────────────────────────────────────────────────────────────
function MounjaroCalculator() {
  const { useState } = React;
  const pennor = [
    { label: "2,5 mg", klick: { 2.5: 60 } },
    { label: "5 mg",   klick: { 2.5: 30, 5.0: 60 } },
    { label: "7,5 mg", klick: { 2.5: 20, 5.0: 40, 7.5: 60 } },
    { label: "10 mg",  klick: { 2.5: 15, 5.0: 30, 7.5: 45, 10.0: 60 } },
    { label: "12,5 mg",klick: { 2.5: 12, 5.0: 24, 7.5: 36, 10.0: 48, 12.5: 60 } },
    { label: "15 mg",  klick: { 2.5: 10, 5.0: 20, 7.5: 30, 10.0: 40, 12.5: 50, 15.0: 60 } },
  ];
  const doser = [2.5, 5.0, 7.5, 10.0, 12.5, 15.0];
  const [pennIdx, setPennIdx] = useState(0);
  const [dos, setDos] = useState(2.5);
  const vald = pennor[pennIdx];
  const klick = vald.klick[dos] || null;

  return (
    <div style={{ background: "var(--peach-pale)", border: "1px solid rgba(229,169,131,0.4)", borderRadius: "var(--radius)", padding: "18px" }}>
      <p style={{ fontSize: "0.82rem", color: "var(--text)", lineHeight: 1.55, marginBottom: 16 }}>
        Välj penna och önskad dos för att se hur många klick du ska vrida fram. Gäller Mounjaro KwikPen, flerdospenna.
      </p>
      <div style={{ marginBottom: 14 }}>
        <div style={{ fontFamily: "Nunito, sans-serif", fontWeight: 700, fontSize: "0.75rem", color: "var(--text-dark)", marginBottom: 6 }}>Välj penna</div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
          {pennor.map((p, i) => (
            <button key={i} onClick={() => { setPennIdx(i); setDos(Object.keys(p.klick).map(Number)[0]); }} style={{
              padding: "6px 12px", borderRadius: "50px", border: "1px solid",
              borderColor: pennIdx === i ? "var(--peach)" : "rgba(87,87,86,0.2)",
              background: pennIdx === i ? "var(--peach)" : "white",
              color: pennIdx === i ? "white" : "var(--text-dark)",
              fontFamily: "Nunito, sans-serif", fontWeight: 700, fontSize: "0.78rem", cursor: "pointer"
            }}>{p.label}</button>
          ))}
        </div>
      </div>
      <div style={{ marginBottom: 20 }}>
        <div style={{ fontFamily: "Nunito, sans-serif", fontWeight: 700, fontSize: "0.75rem", color: "var(--text-dark)", marginBottom: 6 }}>Önskad dos (mg)</div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
          {doser.filter(d => vald.klick[d] !== undefined).map(d => (
            <button key={d} onClick={() => setDos(d)} style={{
              padding: "6px 12px", borderRadius: "50px", border: "1px solid",
              borderColor: dos === d ? "var(--peach)" : "rgba(87,87,86,0.2)",
              background: dos === d ? "var(--peach)" : "white",
              color: dos === d ? "white" : "var(--text-dark)",
              fontFamily: "Nunito, sans-serif", fontWeight: 700, fontSize: "0.78rem", cursor: "pointer"
            }}>{d} mg</button>
          ))}
        </div>
      </div>
      {klick && (
        <div style={{ background: "white", borderRadius: "var(--radius-sm)", padding: "16px", textAlign: "center", border: "1px solid rgba(229,169,131,0.3)" }}>
          <div style={{ fontFamily: "Nunito, sans-serif", fontWeight: 900, fontSize: "2.5rem", color: "var(--peach)", lineHeight: 1 }}>{klick}</div>
          <div style={{ fontFamily: "Nunito, sans-serif", fontWeight: 700, fontSize: "0.82rem", color: "var(--text)", marginTop: 4 }}>klick</div>
          <div style={{ fontSize: "0.78rem", color: "var(--text-muted)", marginTop: 8 }}>Penna {vald.label} · Dos {dos} mg</div>
          <div style={{ fontSize: "0.75rem", color: "var(--text-muted)", marginTop: 4, fontStyle: "italic" }}>Vrid upp långsamt och räkna. Tuschpenna på hjulet hjälper dig hålla koll.</div>
        </div>
      )}
    </div>
  );
}

